// ── Filtra leads que precisam de follow-up ────────────────────────────────
const leads = $input.all();
const resultado = [];

const agora = new Date();
// Ajuste UTC-3 (Belém)
agora.setHours(agora.getHours() - 3);

for (const item of leads) {
  const d = item.json;

  // Pular leads fechados ou perdidos
  const status = (d['Status CRM'] || '').toLowerCase();
  if (status.includes('fechado') || status.includes('perdido')) continue;

  // Calcular horas desde o último contato
  const ultimoContato = new Date(d['Ultimo Contato'] || d['Data/Hora']);
  const diffHoras = (agora - ultimoContato) / (1000 * 60 * 60);

  if (isNaN(diffHoras)) continue;

  let mensagem = null;
  let etapa = null;
  let campoColunaUpdate = null;

  // 1 hora
  if (diffHoras >= 1 && diffHoras < 2 && d['Followup 1h'] !== 'SIM') {
    etapa = '1h';
    campoColunaUpdate = 'Followup 1h';
    mensagem = `Oi ${d.Nome}! Vi que você demonstrou interesse em ter sua loja online. Posso te ajudar com alguma dúvida agora?`;
  }
  // 24 horas
  else if (diffHoras >= 24 && diffHoras < 25 && d['Followup 24h'] !== 'SIM') {
    etapa = '24h';
    campoColunaUpdate = 'Followup 24h';
    mensagem = `${d.Nome}, vi que você ainda não respondeu. Estou aqui pra tirar dúvidas sobre como criar sua loja ${d.Plataforma}. Quando é um bom momento pra conversar?`;
  }
  // 3 dias (72 horas)
  else if (diffHoras >= 72 && diffHoras < 73 && d['Followup 3d'] !== 'SIM') {
    etapa = '3d';
    campoColunaUpdate = 'Followup 3d';
    mensagem = `Olá ${d.Nome}! Queria compartilhar um case de sucesso: uma loja do nicho ${d.Nicho} que lançamos recentemente. Posso te enviar os detalhes?`;
  }
  // 7 dias (168 horas)
  else if (diffHoras >= 168 && diffHoras < 169 && d['Followup 7d'] !== 'SIM') {
    etapa = '7d';
    campoColunaUpdate = 'Followup 7d';
    mensagem = `${d.Nome}, última mensagem da minha parte. Sei que você estava pensando em criar sua loja. Se mudar de ideia ou tiver dúvidas, estou aqui. Abraço!`;
  }

  if (mensagem && d.Telefone) {
    resultado.push({
      json: {
        ...d,
        mensagem_followup: mensagem,
        etapa_followup: etapa,
        coluna_update: campoColunaUpdate
      }
    });
  }
}

console.log(`Follow-up: ${resultado.length} lead(s) para contatar`);
return resultado;
